import numpy as np

def boundary_following(image):
 # Define the 4-way directions
 directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
 # Initialize the chain code
 chain_code = []
 # Iterate over the pixels in the image
 for i in range(image.shape[0]):
 for j in range(image.shape[1]):
 # Check if the current pixel is a boundary point
 if image[i, j] == 255 and (i == 0 or image[i - 1, j] == 0) and (j == 0 or image[i, j - 1] == 0):
 # Add the chain code number to the sequence
 chain_code.append(get_direction(i, j, directions))
 return chain_code

def get_direction(i, j, directions):
 # Calculate the direction of the edge at the current point
 for direction in directions:
 if direction == (0, 1) and i > 0 and j == 0:
 return 0
 elif direction == (1, 0) and i == 0 and j > 0:
 return 1
 elif direction == (0, -1) and i > 0 and j == image.shape[1] - 1:
 return 2
 elif direction == (-1, 0) and i == 0 and j == image.shape[1] - 1:
 return 3
 else:
 continue
 return -1

#include <stdio.h>
#include <stdlib.h>

// Define the 4-way directions
int directions[][2] = {{0, 1}, {1, 0}, {0, -1}, {-1, 0}};

// Function to get the direction of the edge at a point
int get_direction(int i, int j, int directions[][2]) {
 // Calculate the direction of the edge at the current point
 for (int k = 0; k < 4; k++) {
 if (directions[k][0] == 0 && directions[k][1] == 1 && i > 0 && j == 0) {
 return 0;
 } else if (directions[k][0] == 1 && directions[k][1] == 0 && i == 0 && j > 0) {
 return 1;
 } else if (directions[k][0] == 0 && directions[k][1] == -1 && i > 0 && j == 255) {
 return 2;
 } else if (directions[k][0] == -1 && directions[k][1] == 0 && i == 0 && j == 255) {
 return 3;
 } else {
 continue;
 }
 }
 return -1;
}

// Function to perform boundary following
void boundary_following(int image[][256]) {
 // Initialize the chain code
 int chain_code[256];
 int index = 0;
 // Iterate over the pixels in the image
 for (int i = 0; i < 256; i++) {
 for (int j = 0; j < 256; j++) {
 // Check if the current pixel is a boundary point
 if (image[i][j] == 255 && (i == 0 || image[i - 1][j] == 0) && (j == 0 || image[i][j - 1] == 0)) {
 // Add the chain code number to the sequence
 chain_code[index++] = get_direction(i, j, directions);
 }
 }
 }
